const express = require('express');
const path = require('path');

const app = express();
app.use(express.json());

// Serve static files from public
app.use(express.static(path.join(__dirname, '..', 'public')));

// In-memory color state. Default to black.
let currentColor = '#000000';

// GET current color
app.get('/api/color', (req, res) => {
  res.json({ color: currentColor });
});

// POST update color. Expect JSON: { color: "#rrggbb" }
app.post('/api/color', (req, res) => {
  const { color } = req.body || {};
  if (typeof color !== 'string') {
    return res.status(400).json({ error: 'color must be a string' });
  }

  // Basic validation: accept #rgb or #rrggbb hex formats
  const isHex = /^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(color);
  if (!isHex) {
    return res.status(400).json({ error: 'invalid color format. expected hex like #rrggbb' });
  }

  currentColor = color;
  res.json({ color: currentColor });
});

module.exports = app;

