(function () {
  function qs(sel) { return document.querySelector(sel); }

  const helloEl = qs('#hello');
  const colorPicker = qs('#colorPicker');
  const presets = document.querySelectorAll('.preset-btn');

  function setColorOnPage(color) {
    if (!color) return;
    helloEl.style.color = color;
    // ensure colorPicker value is a 7-char hex when possible
    try {
      if (color.startsWith('#')) {
        if (color.length === 4) {
          // convert #rgb to #rrggbb
          const r = color[1];
          const g = color[2];
          const b = color[3];
          colorPicker.value = `#${r}${r}${g}${g}${b}${b}`;
        } else {
          colorPicker.value = color;
        }
      }
    } catch (e) {
      // ignore
    }
  }

  async function fetchColor() {
    try {
      const res = await fetch('/api/color');
      if (!res.ok) return;
      const data = await res.json();
      setColorOnPage(data.color);
    } catch (err) {
      console.error('Error fetching color', err);
    }
  }

  async function persistColor(color) {
    try {
      const res = await fetch('/api/color', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ color })
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        console.error('Failed to save color', err);
      }
    } catch (err) {
      console.error('Error saving color', err);
    }
  }

  document.addEventListener('DOMContentLoaded', function () {
    fetchColor();

    colorPicker.addEventListener('input', function (ev) {
      const color = ev.target.value;
      setColorOnPage(color);
      persistColor(color);
    });

    presets.forEach(btn => {
      btn.addEventListener('click', function () {
        const color = btn.dataset.color;
        setColorOnPage(color);
        try { colorPicker.value = color; } catch (e) {}
        persistColor(color);
      });
    });
  });
})();

