const http = require('http');
const assert = require('assert');
const app = require('../src/server');

function listenOnRandomPort(app) {
  return new Promise((resolve, reject) => {
    const server = app.listen(0, () => {
      const port = server.address().port;
      resolve({ server, port });
    }).on('error', reject);
  });
}

function httpGet(port, path) {
  return new Promise((resolve, reject) => {
    const req = http.get({ hostname: '127.0.0.1', port, path, agent: false }, (res) => {
      let body = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, body, headers: res.headers }));
    }).on('error', reject);
  });
}

function httpPost(port, path, json) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify(json);
    const opts = {
      hostname: '127.0.0.1',
      port,
      path,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(data)
      }
    };
    const req = http.request(opts, (res) => {
      let body = '';
      res.setEncoding('utf8');
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => resolve({ statusCode: res.statusCode, body, headers: res.headers }));
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

(async () => {
  const { server, port } = await listenOnRandomPort(app);
  try {
    // 1) GET default color
    const res1 = await httpGet(port, '/api/color');
    assert.strictEqual(res1.statusCode, 200, 'GET /api/color should return 200');
    const data1 = JSON.parse(res1.body);
    assert.strictEqual(data1.color, '#000000', 'default color should be #000000');

    // 2) POST update color
    const res2 = await httpPost(port, '/api/color', { color: '#ff0000' });
    assert.strictEqual(res2.statusCode, 200, 'POST /api/color should return 200');
    const data2 = JSON.parse(res2.body);
    assert.strictEqual(data2.color.toLowerCase(), '#ff0000', 'response should show updated color');

    // 3) GET again should reflect updated color
    const res3 = await httpGet(port, '/api/color');
    assert.strictEqual(res3.statusCode, 200, 'GET /api/color should return 200 after update');
    const data3 = JSON.parse(res3.body);
    assert.strictEqual(data3.color.toLowerCase(), '#ff0000', 'color should persist in memory after POST');

    // 4) GET index page and ensure it contains "hello world"
    const res4 = await httpGet(port, '/');
    assert.strictEqual(res4.statusCode, 200, 'GET / should return 200');
    assert.ok(res4.body.toLowerCase().includes('hello world'), 'index.html should contain "hello world"');

    console.log('All tests passed');
    server.close(() => process.exit(0));
  } catch (err) {
    console.error('Test failed', err);
    server.close(() => process.exit(1));
  }
})();
